create table users (id bigserial primary key, username varchar(40) not null unique, password_hash varchar(100) not null, role varchar(20) not null, created_at timestamptz not null default now());
create table categories (id bigserial primary key, name varchar(60) not null unique, slug varchar(60) not null unique, icon varchar(40) not null, active boolean not null default true, created_at timestamptz not null default now());
create table places (id bigserial primary key, name varchar(120) not null, zone varchar(100), category_id bigint not null references categories(id), created_by bigint not null references users(id), created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table items (id bigserial primary key, place_id bigint not null references places(id) on delete cascade, author_id bigint not null references users(id), name varchar(120) not null, comment varchar(1000), taste smallint not null check(taste between 1 and 5), price smallint not null check(price between 1 and 5), venue smallint not null check(venue between 1 and 5), created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table item_photos (id bigserial primary key, item_id bigint not null unique references items(id) on delete cascade, object_key varchar(300) not null, thumbnail_key varchar(300) not null, width integer not null, height integer not null, created_at timestamptz not null default now());
create index idx_places_category_id on places(category_id); create index idx_items_place_id_id on items(place_id, id desc); create index idx_items_author_id on items(author_id);
